// // This module performs a division operation on two 2-bit numbers. It calculates the quotient and remainder of the division. If the divisor is zero, it sets the quotient and remainder to non-zero values.
module divider_2bit (  
    input [1:0] dividend,  
    input [1:0] divisor,  
    output reg [1:0] quotient,  
    output reg [1:0] remainder  
);  
    always @(*) begin  
        if (divisor == 2'b00) begin  
            quotient = 2'b00;  
            remainder = 2'b00;  
        end else begin  
            quotient = dividend / divisor;  
            remainder = dividend % divisor;  
        end  
    end  
endmodule
